  ('aboriginal-a5729396-moex-00561', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-110-55d283b0', 'sub-aboriginal-a5729396-04', NULL, 'single_choice', '依憲法及司法院大法官解釋，關於秘密通訊自由的敘述，下列何者錯誤？', '["國家對秘密通訊自由之限制，必須以法律直接規定，不得授權命令為之", "秘密通訊自由乃憲法保障隱私權之具體態樣之一", "限制秘密通訊自由所踐行之程序應合理、正當", "秘密通訊自由旨在確保人民就通訊之有無、對象、時間、方式及內容等事項，有不受國家及他人任 意侵擾之權利"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:48+00:00", "source_pdf_sha1": "93382b4aec10", "answer_pdf_sha1": "56bfa56d5fe2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "605", "s": "0610", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
